INSERT INTO `chatbot_settings` VALUES (1,1,'دستیار بهرام','سلام! من دستیار هوشمند آکادمی بهرام هستم. درباره دوره‌ها، سات یا مسیر رشد حرفه‌ای سوالی دارید؟','تو دستیار هوشمند وب‌سایت بهرام رستمی هستی. پاسخ‌ها را کوتاه، دقیق و به زبان فارسی بده.','پاسخ را مختصر و مفید بده و در صورت نیاز کاربر را به تکمیل فرم تماس راهنمایی کن.','در حال حاضر امکان پاسخ‌گویی وجود ندارد. لطفاً بعداً دوباره تلاش کنید یا اطلاعات تماس خود را بگذارید.',1,1,'2026-07-09 19:20:52','2026-07-09 19:20:52');
/*!40000 ALTER TABLE `chatbot_settings` ENABLE KEYS */;
