INSERT INTO `family_post_blocks` VALUES (1,1,'text',0,'سلام خانواده! من بهرام هستم. خوشحالم که اینجا هستید — از امروز هر هفته اینجا با هم حرف می‌زنیم و مسیر رشد را جلو می‌بریم.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"welcome-text\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(2,2,'text',0,'یادتون باشه: پیشرفت واقعی از اقدام کوچک و مداوم شروع می‌شه. این هفته یک کار کوچک انتخاب کنید و انجامش بدید — بعد توی کامنت‌ها برام بنویسید.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"weekly-focus\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(3,3,'text',0,'🎙️ پادکست این هفته: دربارهٔ تمرکز عمیق و حذف حواس‌پرتی — گوش کن و نظرت رو بنویس.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"voice-podcast\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(4,3,'audio',1,NULL,1,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(5,4,'text',0,'پیام ویدیویی کوتاه از بهرام — یک نکتهٔ عملی برای امروز.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"video-message\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(6,4,'video',1,NULL,2,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(7,5,'text',0,'ویدیوی عمودی ۹:۱۶ — تست نمایش در فید (مثل استوری/ریels).',NULL,NULL,NULL,NULL,'{\"demo_key\": \"video-vertical-portrait\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(8,5,'video',1,NULL,3,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(9,6,'text',0,'لحظه‌ای از پشت صحنهٔ کار — گاهی مسیر، مهم‌تر از مقصد است.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"image-moment\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(10,6,'image',1,NULL,4,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(11,7,'text',0,'آلبوم این هفته: سه لحظه از مسیر رشد خانواده.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"image-album-journey\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(12,7,'image',1,NULL,4,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(13,7,'image',2,NULL,5,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(14,7,'image',3,NULL,6,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(15,8,'text',0,'مقالهٔ پیشنهادی این هفته — عمیق‌تر بخون و برام نظر بده.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"article-insight\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(16,8,'article_reference',1,NULL,NULL,26,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(17,9,'text',0,'خلاصهٔ هفته (ترکیبی): متن + صوت + عکس — همه با هم.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"mixed-weekly-recap\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(18,9,'audio',1,NULL,1,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(19,9,'image',2,NULL,5,NULL,NULL,NULL,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(20,10,'text',0,'این هفته یک تعهد کوچک بردار — دکمهٔ زیر رو بزن.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-commitment\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(21,10,'action_reference',999,NULL,NULL,NULL,NULL,1,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(22,11,'text',0,'بررسی سریع: تمرین دیروز رو انجام دادی؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-confirmation\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(23,11,'action_reference',999,NULL,NULL,NULL,NULL,2,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(24,12,'text',0,'نظرسنجی: بزرگ‌ترین چالش این هفته‌ات چی بود؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-poll\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(25,12,'action_reference',999,NULL,NULL,NULL,NULL,3,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(26,13,'text',0,'از ۱ تا ۱۰، امروز چقدر احساس پیشرفت کردی؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-scale\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(27,13,'action_reference',999,NULL,NULL,NULL,NULL,4,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(28,14,'text',0,'عدد بگو: چند دقیقه امروز روی هدف اصلی‌ات کار کردی؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-number\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(29,14,'action_reference',999,NULL,NULL,NULL,NULL,5,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(30,15,'text',0,'یک جمله بنویس: امروز چی یاد گرفتی؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-short-text\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(31,15,'action_reference',999,NULL,NULL,NULL,NULL,6,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(32,16,'text',0,'چندتایی انتخاب کن: کدوم حوزه‌ها این هفته برات اولویت بود؟',NULL,NULL,NULL,NULL,'{\"demo_key\": \"action-multi-choice\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(33,16,'action_reference',999,NULL,NULL,NULL,NULL,7,NULL,'2026-07-15 19:46:56','2026-07-15 19:46:56'),(34,17,'text',0,'سارا جان ممنون از انرژی‌ات! ❤️ خوشحالم که اینجایی — هر هفته با هم جلو می‌ریم.',NULL,NULL,NULL,NULL,'{\"demo_key\": \"reply-to-member\"}','2026-07-15 19:46:56','2026-07-15 19:46:56'),(35,18,'text',0,'ساسباسایبایبایبا',NULL,NULL,NULL,NULL,NULL,'2026-07-15 20:04:07','2026-07-15 20:04:07'),(36,19,'text',0,'تست',NULL,NULL,NULL,NULL,NULL,'2026-07-16 16:57:58','2026-07-16 16:57:58'),(37,20,'text',0,'تست 2',NULL,NULL,NULL,NULL,NULL,'2026-07-16 17:00:32','2026-07-16 17:00:32'),(39,22,'text',0,'صاا',NULL,NULL,NULL,NULL,NULL,'2026-07-16 18:02:38','2026-07-16 18:02:38'),(43,23,'text',0,'❤❤❤💚💚',NULL,NULL,NULL,NULL,NULL,'2026-07-16 18:28:33','2026-07-16 18:28:33'),(44,24,'text',0,'❤❤❤💚💚',NULL,NULL,NULL,NULL,NULL,'2026-07-16 18:33:31','2026-07-16 18:33:31'),(48,21,'text',0,'اشاساالدالبذب',NULL,NULL,NULL,NULL,NULL,'2026-07-16 19:09:57','2026-07-16 19:09:57'),(65,25,'image',0,NULL,22,NULL,NULL,NULL,NULL,'2026-07-16 19:47:42','2026-07-16 19:47:42'),(66,25,'text',1,'اعصانیمیییییییببببببببببببببببببببببسیزسزسیزسیزب🙄🙄😶☘',NULL,NULL,NULL,NULL,NULL,'2026-07-16 19:47:42','2026-07-16 19:47:42'),(67,26,'text',0,'o,fd',NULL,NULL,NULL,NULL,NULL,'2026-07-16 20:01:14','2026-07-16 20:01:14'),(68,27,'text',0,'dfvdfvdfvdfvdfv',NULL,NULL,NULL,NULL,NULL,'2026-07-16 20:01:22','2026-07-16 20:01:22'),(78,28,'text',0,'سلام خانواده! امروز درباره «طزرطر» با هم صحبت می‌کنیم.\n\n— بهرام',NULL,NULL,NULL,NULL,NULL,'2026-07-16 22:00:19','2026-07-16 22:00:19'),(80,30,'text',0,'سلام خانواده! امروز درباره «تست» با هم صحبت می‌کنیم.\n\n— بهرام',NULL,NULL,NULL,NULL,NULL,'2026-07-16 22:40:29','2026-07-16 22:40:29');
