INSERT INTO `mini_courses` VALUES (1,4,'alfabe-kampain-nevisi','مینی‌دوره الفبای کمپین‌نویسی','ورود سریع به تفکر کمپین‌محور','الفبای کمپین‌نویسی؛ از ایده تا پیام، ساختار و اجرای اولیه.','<p>در این مینی‌دوره با مفاهیم پایه کمپین‌نویسی آشنا می‌شوید: تعریف کمپین، تفاوت آن با تولید محتوای پراکنده، ساخت پیام مرکزی و طراحی مسیر کوتاه برای جذب مخاطب.</p><p>این دوره نقطه شروعی است قبل از ورود به مسیر اصلی کمپین‌نویسی آکادمی بهرام.</p>','/storage/media/2026/07/01kx63nw6b1pwh4y84q5jvjhtg.webp',NULL,'oyt346k','مقدماتی','رایگان',1,1,1,NULL,NULL,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(2,5,'senario-nevisi','مینی‌دوره سناریونویسی','ساختار روایت برای ویدیو و کمپین','سناریونویسی کاربردی برای ویدیوهای آموزشی و تبلیغاتی.','<p>در این مینی‌دوره یاد می‌گیرید چطور یک سناریوی کوتاه و مؤثر بنویسید: قلاب آغازین، رویداد اصلی، تبدیل مخاطب و بستن داستان.</p><p>مناسب برای کسانی که می‌خواهند قبل از تولید ویدیو، ساختار روایت را درست بچینند.</p>','/storage/media/2026/07/01kx63t8e2xtbb5eq6kmv9zs2k.webp',NULL,'falji09','مقدماتی','رایگان',2,1,1,NULL,NULL,'2026-07-11 21:45:25','2026-07-11 21:45:25');
/*!40000 ALTER TABLE `mini_courses` ENABLE KEYS */;
UNLOCK TABLES;

