INSERT INTO `products` VALUES (1,'دوره کمپین‌نویسی حرفه‌ای','campaign-writing','normal','<p>در این دوره با ساختار کمپین، متن‌نویسی فروش و اجرای عملی آشنا می‌شوید.</p>','نوشتن کمپین فروش مؤثر',2500000,1990000,1,'fixed',2000000,1,0,'public',0,NULL,NULL,1,1,'مسیر حرفه‌ای','۱۰ فصل','/course/campaign-writing',NULL,'66fedcb3595f23d5f6bbc52a',NULL,'دوره کمپین‌نویسی | بهرام رستمی','آموزش کمپین‌نویسی و فروش آنلاین با بهرام رستمی.','2026-07-09 19:20:52','2026-07-09 19:22:42'),(2,'پکیج رشد فروش','sales-growth-package','package','<p>شامل دوره کمپین‌نویسی، چک‌لیست اجرا و پشتیبانی محدود.</p>','مجموعه دوره‌ها و فایل‌های عملی برای افزایش فروش.',4900000,NULL,0,NULL,NULL,1,0,'public',0,NULL,NULL,0,0,NULL,NULL,NULL,'/storage/media/site/landscape-session.webp',NULL,NULL,'پکیج رشد فروش','پکیج جامع آموزش و اجرای فروش آنلاین.','2026-07-09 19:20:52','2026-07-11 21:45:25'),(3,'سمینار زعفرانیه تهران','seminar-smynar-zaafranyh-thran','event',NULL,'سمینار زعفرانیه؛ یک تجربه متفاوت برای رشد، یادگیری و ارتباط با افراد هم‌مسیر\n\nدر این سمینار، مجموعه‌ای از تجربیات، بینش‌ها و استراتژی‌های کاربردی ارائه می‌شود تا شرکت‌کنندگان بتوانند مسیر رشد شخصی و حرفه‌ای خود را با دیدی تازه‌تر ادامه دهند...',8900000,NULL,0,NULL,NULL,1,0,'public',0,NULL,NULL,0,0,NULL,NULL,'/seminars/smynar-zaafranyh-thran','/storage/media/site/social-01.jpg',NULL,NULL,NULL,NULL,'2026-07-10 10:24:09','2026-07-15 19:46:55'),(4,'مینی‌دوره الفبای کمپین‌نویسی','mini-course-alfabe-kampain-nevisi','mini_course',NULL,'الفبای کمپین‌نویسی؛ از ایده تا پیام، ساختار و اجرای اولیه.',0,NULL,0,NULL,NULL,1,0,'public',0,NULL,NULL,0,0,NULL,NULL,'/mini-courses/alfabe-kampain-nevisi','/storage/media/2026/07/01kx63nw6b1pwh4y84q5jvjhtg.webp',NULL,NULL,NULL,NULL,'2026-07-11 21:45:25','2026-07-15 19:46:55'),(5,'مینی‌دوره سناریونویسی','mini-course-senario-nevisi','mini_course',NULL,'سناریونویسی کاربردی برای ویدیوهای آموزشی و تبلیغاتی.',0,NULL,0,NULL,NULL,1,0,'public',0,NULL,NULL,0,0,NULL,NULL,'/mini-courses/senario-nevisi','/storage/media/2026/07/01kx63t8e2xtbb5eq6kmv9zs2k.webp',NULL,NULL,NULL,NULL,'2026-07-11 21:45:25','2026-07-15 19:46:55');
