DROP TABLE IF EXISTS `seminars`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `seminars` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date` timestamp NULL DEFAULT NULL,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `cover_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cover_image_mobile` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `product_id` bigint unsigned DEFAULT NULL,
  `price` int unsigned DEFAULT NULL,
  `sale_price` int unsigned DEFAULT NULL,
  `capacity` int unsigned DEFAULT NULL,
  `banner_available` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `banner_available_mobile` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `banner_full` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `banner_full_mobile` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `promo_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `seminars_slug_unique` (`slug`),
  KEY `seminars_product_id_foreign` (`product_id`),
  CONSTRAINT `seminars_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
