INSERT INTO `seminars` VALUES (1,'سمینار زعفرانیه تهران','smynar-zaafranyh-thran','2026-07-24 19:46:00','زعفرانیه','سمینار زعفرانیه؛ یک تجربه متفاوت برای رشد، یادگیری و ارتباط با افراد هم‌مسیر\n\nدر این سمینار، مجموعه‌ای از تجربیات، بینش‌ها و استراتژی‌های کاربردی ارائه می‌شود تا شرکت‌کنندگان بتوانند مسیر رشد شخصی و حرفه‌ای خود را با دیدی تازه‌تر ادامه دهند.\n\nاین رویداد فرصتی است برای حضور در یک فضای الهام‌بخش، یادگیری از تجربه‌های واقعی و ایجاد ارتباط با افرادی که به دنبال ساختن آینده‌ای بزرگ‌تر هستند.\n\nظرفیت حضور در سمینار محدود است و ثبت‌نام تنها تا تکمیل ظرفیت ادامه خواهد داشت.','/storage/media/site/social-01.jpg',NULL,'published',3,8900000,NULL,NULL,'/storage/media/2026/07/01kx44z2tqbxdz8jfnc08n7mx8.webp','/storage/media/2026/07/01kxahqjnef8wmv5c7btf6hjej.webp','/storage/media/2026/07/01kx468m91vqw94kq786w50376.webp','/storage/media/site/seminar-promo-mobile-full.webp',1,'2026-07-10 10:24:09','2026-07-19 01:16:46');
/*!40000 ALTER TABLE `seminars` ENABLE KEYS */;
UNLOCK TABLES;

