INSERT INTO `settings` VALUES (1,'chatbot','config','{\"enabled\": true, \"cta_phone\": true, \"cta_pricing\": true, \"cta_whatsapp\": true, \"assistant_name\": \"دستیار بهرام\", \"require_captcha\": true, \"welcome_message\": \"سلام! من دستیار هوشمند آکادمی بهرام هستم. درباره دوره‌ها، سات یا مسیر رشد حرفه‌ای سوالی دارید؟\", \"cta_consultation\": true, \"honeypot_enabled\": true, \"global_hourly_cap\": 100, \"quick_suggestions\": [{\"id\": \"courses\", \"label\": \"دوره‌های آکادمی بهرام چیست؟\", \"response\": \"آکادمی بهرام دوره‌های تخصصی در حوزه‌های فروش، بازاریابی، سات و رشد حرفه‌ای ارائه می‌دهد. برای مشاهده لیست دوره‌ها به صفحه «دوره‌ها» یا «آکادمی» مراجعه کنید.\"}, {\"id\": \"consultation\", \"label\": \"چطور مشاوره یا ثبت‌نام کنم؟\", \"response\": \"برای مشاوره رایگان می‌توانید از دکمه «مشاوره رایگان» در همین چت، تماس تلفنی یا واتساپ استفاده کنید. تیم ما در اولین فرصت با شما هماهنگ می‌کند.\"}, {\"id\": \"saat\", \"label\": \"سات (SAT) چیست و چطور آماده شوم؟\", \"response\": \"سات آزمون استاندارد پذیرش دانشگاه در آمریکا است. آکادمی بهرام برنامه آمادگی سات با مشاوره مسیر، منابع و کلاس‌های تخصصی دارد. برای جزئیات به صفحه «سات» مراجعه کنید.\"}, {\"id\": \"support\", \"label\": \"پشتیبانی و ساعات پاسخگویی\", \"response\": \"ساعات پاسخگویی و راه‌های تماس در صفحه «تماس با ما» یا از طریق همین چت در دسترس است. در ساعات اداری معمولاً پاسخگویی سریع‌تر است.\"}], \"rate_limit_per_hour\": 10, \"system_prompt_extra\": \"تو دستیار هوشمند وب‌سایت بهرام رستمی هستی. پاسخ‌ها را کوتاه، دقیق و به زبان فارسی بده.\", \"max_history_messages\": 8, \"rate_limit_per_minute\": 3, \"operator_rate_limit_per_hour\": 10, \"operator_rate_limit_per_minute\": 3}','2026-07-09 19:20:52','2026-07-15 19:46:55'),(2,'cache','integrations','{\"arvan_domain\": \"fashio.ir\", \"cdn_provider\": \"cloudflare\", \"revalidate_secret\": \"bahram-dev-revalidate-secret\", \"arvan_media_domain\": \"cdn.fashio.ir\", \"cloudflare_zone_id\": \"\", \"revalidate_webhook_url\": \"http://localhost:3000/api/revalidate\"}