INSERT INTO `sms_event_configs` VALUES (1,'otp','کد یک‌بارمصرف (OTP)','ارسال کد ورود به پنل دانشجو',1,'کد ورود شما به آکادمی بهرام رستمی: {code}\\nاین کد را در اختیار دیگران قرار ندهید.','313685',1,'melipayamak',1,20,1,'2026-07-09 19:20:52','2026-07-19 22:53:08'),(2,'purchase_confirmation','تأیید خرید / پرداخت موفق','پس از پرداخت موفق و تکمیل سفارش',1,'کاربر عزیز، خرید شما با موفقیت ثبت شد. کد دسترسی شما: {code}',NULL,0,NULL,0,NULL,2,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(3,'license_created','صدور لایسنس SpotPlayer','پس از صدور لایسنس SpotPlayer (جدا از پیامک خرید)',0,'سلام {name}، لایسنس دوره {product_title} صادر شد. کد: {code}',NULL,0,NULL,0,NULL,3,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(4,'welcome','خوش‌آمدگویی (اولین ورود)','اولین ورود دانشجو به پنل',1,'سلام {name} عزیز؛ به آکادمی بهرام رستمی خوش آمدی! برای شروع به پنل کاربری خودت سر بزن.',NULL,0,NULL,0,NULL,4,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(5,'ticket_created','ثبت تیکت پشتیبانی','تأیید ثبت تیکت برای دانشجو',0,'تیکت پشتیبانی شما با موضوع «{subject}» ثبت شد. به‌زودی پاسخ می‌دهیم.',NULL,0,NULL,0,NULL,5,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(6,'ticket_reply','پاسخ ادمین به تیکت','اطلاع‌رسانی پاسخ پشتیبانی به دانشجو',0,'پاسخ جدید برای تیکت «{subject}» در پنل دانشجو ثبت شد.',NULL,0,NULL,0,NULL,6,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(7,'identity_verification_submitted','ثبت درخواست احراز هویت','پس از ارسال مدارک احراز هویت توسط دانشجو',1,'سلام {name}، درخواست تأیید حساب شما ثبت شد و در صف بررسی قرار گرفت.',NULL,0,NULL,0,NULL,7,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(8,'identity_verification_approved','تأیید احراز هویت','پس از تأیید مدارک توسط اپراتور',1,'سلام {name}، حساب شما با موفقیت تأیید شد.',NULL,0,NULL,0,NULL,8,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(9,'identity_verification_needs_correction','نیاز به اصلاح مدارک احراز هویت','وقتی مدارک نیاز به اصلاح دارند',1,'سلام {name}، برای تکمیل تأیید حساب، لازم است مدارک خود را اصلاح کنید. جزئیات در پنل کاربری شماست.',NULL,0,NULL,0,NULL,9,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(10,'identity_verification_rejected','رد احراز هویت','وقتی درخواست احراز هویت رد می‌شود',1,'سلام {name}، متأسفانه درخواست تأیید حساب شما رد شد. در صورت نیاز با پشتیبانی تماس بگیرید.',NULL,0,NULL,0,NULL,10,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(11,'sat_membership_activated','فعال‌سازی عضویت سات','وقتی عضویت سات پس از تأیید هویت فعال می‌شود',1,'سلام {name}، عضویت سات شما فعال شد.',NULL,0,NULL,0,NULL,11,'2026-07-11 21:45:25','2026-07-11 21:45:25'),(12,'ownership_verification_locked','قفل تطبیق شماره موبایل','پس از قفل شدن تطبیق شماره به‌دلیل تلاش‌های ناموفق',1,'سلام {name}، امکان تطبیق شماره موبایل موقتاً محدود شده است. لطفاً با پشتیبانی تماس بگیرید.',NULL,0,NULL,0,NULL,12,'2026-07-11 21:45:25','2026-07-11 21:45:25');
