  `role` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'دانشجو',
  `before_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `after_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
