/*!40000 ALTER TABLE `student_testimonials` DISABLE KEYS */;
INSERT INTO `student_testimonials` VALUES (1,'sara-r','سارا ر.','مشاور کسب‌وکار','مخاطب خاموش، درآمد ناپایدار','کمپین ماهانه، لیست انتظار ۳ ماهه','با ساختن یک روایت منسجم و کمپین‌های ماهانه، مسیر جذب مشتری برای سارا قابل پیش‌بینی شد.',NULL,NULL,'لیست انتظار','۳ ماه','سارا تخصص داشت، اما حضورش پراکنده بود. هر چند وقت یک‌بار پستی می‌گذاشت، گاهی\r\nفروش می‌آمد و گاهی نه. درآمد، تابعِ شانس بود.\r\n\r\n## نقطه‌ی شروع\r\n\r\nاولین کاری که کردیم، روشن‌کردنِ **موضع** بود: سارا برای چه کسی و درباره‌ی چه\r\nچیزی حرف می‌زند. همین یک تصمیم، نیمی از سردرگمی را حذف کرد.\r\n\r\n## چه چیزی عوض شد؟\r\n\r\n- یک ریتمِ ماهانه‌ی کمپین جای پست‌های پراکنده را گرفت.\r\n- هر کمپین یک قوسِ روشن داشت: از مشکل تا دعوت.\r\n- پیگیریِ بعد از کمپین، فروش‌های جامانده را برگرداند.\r\n\r\n> «اولین باری بود که می‌دانستم ماه بعد قرار است چه اتفاقی بیفتد.»\r\n\r\nنتیجه؟ مسیرِ جذبِ مشتری قابل پیش‌بینی شد و سارا به لیستِ انتظارِ سه‌ماهه رسید.','/storage/media/site/testimonial-01.webp',0,1,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(2,'amir-h','امیر ه.','طراح تجربه','پشتِ نمونه‌کارها پنهان','صدای مرجع در حوزه','امیر با کمپین‌های موضوعی، مخاطب مناسب خود را پیدا کرد و جایگاه حرفه‌ای‌اش تثبیت شد.',NULL,NULL,'پروژه‌های ورودی','۴ برابر','امیر کارش خوب بود، اما خودش را پشتِ نمونه‌کارها پنهان کرده بود. مخاطب فقط\r\nتصویر می‌دید، نه طرزِ فکر.\r\n\r\n## تغییرِ زاویه\r\n\r\nبه‌جای نمایشِ صرفِ کار، شروع کردیم به نوشتنِ **چرایی** تصمیم‌های طراحی. هر\r\nپروژه تبدیل شد به یک روایتِ کوتاه از مسئله و انتخاب.\r\n\r\n## نتیجه\r\n\r\n- مخاطب به طرزِ فکرِ امیر علاقه‌مند شد، نه فقط خروجی.\r\n- پروژه‌های ورودی چهار برابر شد و کیفیتِ مشتری‌ها بالا رفت.\r\n- امیر به یک صدای مرجع در حوزه‌اش تبدیل شد.\r\n\r\n> «وقتی طرزِ فکرم را گفتم، آدم‌های درست پیدایم کردند.»','/storage/media/site/testimonial-03.webp',1,1,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(3,'nazanin-k','نازنین ک.','مربی تغذیه','جلسات پراکنده','برنامه‌های گروهی پر','نازنین با روایت تخصصی و پیام یکپارچه، از فروش تک‌جلسه‌ای به برنامه‌های گروهی رسید.',NULL,NULL,'درآمد ماهانه','۲.۵ برابر','نازنین وقتش را با جلسه‌های تک‌نفره پر کرده بود؛ پرمشغله بود اما درآمدش سقف\r\nداشت و خسته شده بود.\r\n\r\n## بازطراحی پیشنهاد\r\n\r\nپیشنهادش را از «جلسه‌ی تکی» به یک **برنامه‌ی گروهیِ مسیردار** تغییر دادیم —\r\nبا یک روایتِ روشن از تغییری که ایجاد می‌کند.\r\n\r\n## نتیجه\r\n\r\n- ظرفیتش از تعدادِ ساعت‌ها آزاد شد.\r\n- برنامه‌های گروهی پر شدند و درآمد ماهانه ۲.۵ برابر شد.\r\n- کیفیتِ نتیجه‌ی مراجعان هم بهتر شد، چون در گروه انگیزه بیشتر بود.\r\n\r\n> «دیگر وقتم را نمی‌فروشم؛ تحول می‌فروشم.»','/storage/media/site/testimonial-02.webp',2,1,'2026-07-09 19:20:52','2026-07-09 19:20:52'),(4,'reza-m','رضا م.','مدرس زبان','قیمت‌گذاری بر اساس رقبا','جایگاه پریمیوم','رضا با تثبیت تخصص و روایت متمایز، از رقابت قیمتی خارج شد و به جایگاه پریمیوم رسید.',NULL,NULL,'نرخ هر دوره','۳ برابر','رضا در یک رقابتِ قیمتیِ فرسایشی گیر کرده بود؛ هر بار یک نفر ارزان‌تر پیدا\r\nمی‌شد.\r\n\r\n## خروج از رقابت قیمتی\r\n\r\nبه‌جای رقابت بر سرِ قیمت، روی **تمایزِ روش** کار کردیم: رضا چه چیزی را متفاوت\r\nانجام می‌دهد که نتیجه را تضمین‌پذیرتر می‌کند؟\r\n\r\n## نتیجه\r\n\r\n- مخاطب دیگر رضا را با بقیه مقایسه نمی‌کرد.\r\n- نرخِ هر دوره سه برابر شد، با تقاضای بیشتر.\r\n- رضا توانست تعداد دانشجو را کم و کیفیت را زیاد کند.\r\n\r\n> «وقتی فهمیدم چه چیزی‌ام منحصربه‌فرد است، قیمت دیگر بحث نبود.»','/storage/media/site/testimonial-04.webp',3,1,'2026-07-09 19:20:52','2026-07-09 19:20:52');
/*!40000 ALTER TABLE `student_testimonials` ENABLE KEYS */;
UNLOCK TABLES;

